#include "interface.h"
#include "lz4.h"

namespace {
constexpr std::size_t kChunkSize = 1 << 14;
constexpr std::size_t kMaxCompressedChunkSize = LZ4_compressBound(kChunkSize);
}

int compress_chunks(const std::string& input, std::vector<std::string>& chunks) {
  chunks.clear();
  chunks.reserve((input.size() + kChunkSize - 1) / kChunkSize);
  int total = 0;
  std::string compressed;
  compressed.resize(kMaxCompressedChunkSize);
  for (std::size_t offset = 0; offset < input.size(); offset += kChunkSize) {
    const std::size_t take = std::min(kChunkSize, input.size() - offset);
    const int n = LZ4_compress_default(
        input.data() + offset, compressed.data(), static_cast<int>(take), kMaxCompressedChunkSize);
    if (n <= 0) {
      return -1;
    }
    chunks.emplace_back(compressed.data(), static_cast<std::size_t>(n));
    total += n;
  }
  return total;
}
